INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-5ff21eeb-moex-00294', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '依納稅者權利保護法關於行政規則及解釋函令之規定，下列敘述何者正確？', '["主管機關所發布之行政規則及解釋函令，可以增加法律所未明定之納稅義務", "法律所未明定而屬規範執行法律所必要之技術性、細節性事項，不能用行政規則或解釋函令予 以補充", "法律未明定之稅捐減免事項，因為對人民有利，故以行政規則或解釋函令補充，亦無違租稅法 律主義", "解釋函令未依行政程序法第160條第2項、政府資訊公開法第8條或其他適當方式公開者，稅 捐稽徵機關不得作為他案援用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00295', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '有關稅捐稽徵機關為稅捐核課或處罰前，是否應給予納稅者事先說明之機會，下列敘述何者錯誤：', '["情況急迫，如予陳述意見之機會，顯然違背公益者，可不給予事先說明之機會", "應否給予事先說明之機會，應以逃漏稅捐之金額是否巨大或違規情節是否重大來決定，逃漏稅 捐之金額微小或違規情節輕微，就可不給予事先說明之機會", "行政處分所根據之事實，客觀上明白足以確認者，可不給予事先說明之機會", "對稅捐核課處分不服，因須經過復查程序，故稅捐稽徵機關為稅捐核課前，可不給予納稅者事 先說明之機會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00296', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '下列有關稅捐稽徵之敘述，何者錯誤？', '["所得稅、營業稅屬於國稅；地價稅、房屋稅、汽機車牌照稅屬於地方稅", "財政部北區國稅局屬於國稅機關；南投縣政府稅務局屬於地方稅務機關", "關稅、所得稅、土地增值稅屬於國稅；營業稅、地價稅屬於地方稅", "不服國稅局的復查決定，向財政部提起訴願；不服地方稅務機關的復查決定，向該管地方縣（市） 政府提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00297', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '依納稅者權利保護法之規定，下列敘述何者正確？', '["如果某一種規定（例如違反義務之行為，非出於故意或過失者，不予處罰），在行政罰法與納稅 者權利保護法都有規定，因為行政罰法是特別法，故應優先適用行政罰法", "只有稅法主管機關為特定政策需要，才可以規定租稅優惠", "租稅法律如果文義上有疑義，只能修法解決，不能用解釋函令加以闡明，否則有違租稅法律主義", "租稅優惠規定之擬訂，應舉行公聽會並提出稅式支出評估，且應明定實施年限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00298', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '依稅捐稽徵法第33條規定，稅捐稽徵人員對下列人員查調納稅義務人之財產、所得、營業、納稅 等資料時，可以拒絕？', '["納稅義務人授權代理人或辯護人", "納稅義務人本人或其繼承人", "納稅義務人之債權人已取得民事確定判決或其他執行名義者", "納稅義務人之已離婚的前配偶"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00299', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '關於稅捐行政救濟，下列敘述何者錯誤？', '["納稅義務人對於核定稅捐之處分如有不服，應先申請復查", "依核定稅額通知書所載有應納稅額或應補徵稅額者，應於繳款書送達後之翌日起 30 日內，申 請復查", "稅捐稽徵機關對有關復查之申請，應於接到申請書之翌日起2個月內復查決定。期間屆滿，稅 捐稽徵機關仍未作成決定者，納稅義務人得逕行提起訴願", "稅捐稽徵機關對有關復查之申請，應於接到申請書之翌日起2個月內復查決定。稅捐稽徵機關 逾期始作成決定者，該決定仍有效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00300', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '納稅義務人甲遭受補稅及罰鍰處分時，下列敘述何者錯誤？', '["甲會收到核定稅額通知書、稅款繳款書、裁處書及罰鍰繳款書", "甲對補稅及罰鍰處分均不服時，得同時對該二者申請復查", "甲如僅對補稅部分提起行政救濟，則罰鍰部分會因其未提起行政救濟而確定，嗣後不會再變更", "甲未繳納稅款，也可以申請復查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00301', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '關於「核課稅捐處分」之行政救濟程序，下列敘述何者錯誤？', '["申請復查是否逾期，係以郵寄申請書之郵戳日期為準，不以受理復查機關實際收文日期為準", "提起訴願是否逾期，不以郵寄訴願書之郵戳日期為準，而以原處分機關或受理訴願機關實際收 受訴願書之日期為準", "其行政救濟程序有三：「復查」、「訴願」、「行政訴訟」", "現行行政訴訟採兩級審，第一級為「高等行政法院」，第二級為「最高行政法院」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00302', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '稅捐稽徵法關於強制執行之規定，下列敘述何者錯誤？', '["納稅義務人收到稅款繳款書，只要依稅捐稽徵法第 35 條規定申請復查者，稅捐稽徵機關就不 能移送強制執行", "納稅義務人對復查決定不服，依法提起訴願者，稅捐稽徵機關就不能移送強制執行", "納稅義務人對罰鍰處分不服，在行政救濟程序終結前，稅捐稽徵機關都不能將該罰鍰移送強制 執行", "稅捐稽徵機關，認為移送強制執行不當者，得撤回執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00303', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '依稅捐稽徵法第44條及財政部解釋函令，下列何者錯誤？', '["營利事業依法規定應給與他人統一發票而未給與，應按查明認定之總額，處5%罰鍰，但最高不 得超過新臺幣100萬元", "小規模營業人每月銷售額雖已達使用統一發票之銷售額標準，但在稅捐稽徵機關變更核定其使 用統一發票前，沒給顧客統一發票，也不能依稅捐稽徵法第44條規定處罰", "營利事業向股東借款，也要給與統一發票，否則應依稅捐稽徵法第44條規定處罰", "營利事業銷貨漏開統一發票，係同時觸犯稅捐稽徵法第 44 條與加值型與非加值型營業稅法第 51條第3款規定，但得採擇一從重處罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
